using namespace std;

bool is_prime(long long num) {
    if (num <= 1) return false;
    if (num == 2) return true;
    if (num % 2 == 0) return false;
    for (long long i = 3; i * i <= num; i += 2) {
        if (num % i == 0) return false;
    }
    return true;
}

long long solve(std::vector<long long> nums) {
    int n = nums.size();
    if (n == 1) return 0;

    unordered_map<long long, vector<int>> prime_to_indices;
    for (int i = 0; i < n; ++i) {
        long long num = nums[i];
        if (is_prime(num)) {
            prime_to_indices[num].push_back(i);
        }
    }

    unordered_map<long long, vector<int>> divisible_indices;
    for (int i = 0; i < n; ++i) {
        long long num = nums[i];
        for (auto& [p, _] : prime_to_indices) {
            if (num % p == 0) {
                divisible_indices[p].push_back(i);
            }
        }
    }

    vector<int> dist(n, INT_MAX);
    dist[0] = 0;
    queue<int> q;
    q.push(0);

    while (!q.empty()) {
        int u = q.front();
        q.pop();

        // Check adjacent moves
        if (u + 1 < n && dist[u + 1] > dist[u] + 1) {
            dist[u + 1] = dist[u] + 1;
            q.push(u + 1);
        }
        if (u - 1 >= 0 && dist[u - 1] > dist[u] + 1) {
            dist[u - 1] = dist[u] + 1;
            q.push(u - 1);
        }

